// auth presence.
func isSyncAccessWarning(err error) (*accessWarning, bool) { return nil, false }

// classifyAPIError maps API errors to structured exit codes with actionable hints.
func classifyAPIError(err error) error {
	msg := err.Error()
	switch {
	case strings.Contains(msg, "HTTP 409"):
		// 409 Conflict = resource already exists. For agents retrying creates, this is success.
		fmt.Fprintln(os.Stderr, "already exists (no-op)")
		return nil
	case strings.Contains(msg, "HTTP 401"):
		return authErr(fmt.Errorf("%w\nhint: check your API credentials."+
			"\n      Run 'food52-pp-cli doctor' to check auth status.", err))
	case strings.Contains(msg, "HTTP 403"):
		return authErr(fmt.Errorf("%w\nhint: permission denied. Your credentials are valid but lack access to this resource."+
			"\n      Check that your API key has the required permissions."+
			"\n      Run 'food52-pp-cli doctor' to check auth status.", err))
	case strings.Contains(msg, "HTTP 404"):
		return notFoundErr(fmt.Errorf("%w\nhint: resource not found. Run the 'list' command to see available items", err))
	case strings.Contains(msg, "HTTP 429"):
		return rateLimitErr(err)
	default:
		return apiErr(err)
	}
}

// emitPageFetch writes a one-line ndjson progress event to stderr for each
// fetched page, or a friendly status line when --human-friendly is on.
// Hand-written commands (food52 sync, listing pagers) call this so agents
// streaming stderr can show real-time progress without parsing free text.
func emitPageFetch(page int) {
	if humanFriendly {
		fmt.Fprintf(os.Stderr, "fetching page %d...\n", page)
	} else {
		fmt.Fprintf(os.Stderr, `{"event":"page_fetch","page":%d}`+"\n", page)
	}
}

// levenshteinDistance computes the edit distance between two strings using a two-row DP approach.
func levenshteinDistance(a, b string) int {
	if len(a) == 0 {
		return len(b)
	}
	if len(b) == 0 {
		return len(a)
	}
	if len(a) < len(b) {
		a, b = b, a
	}
	prev := make([]int, len(b)+1)
	curr := make([]int, len(b)+1)
	for j := range prev {
		prev[j] = j
	}
	for i := 1; i <= len(a); i++ {
		curr[0] = i
		for j := 1; j <= len(b); j++ {
			cost := 1
			if a[i-1] == b[j-1] {
				cost = 0
			}
			ins := curr[j-1] + 1
			del := prev[j] + 1
			sub := prev[j-1] + cost
			min := ins
			if del < min {
				min = del
			}
			if sub < min {
				min = sub
			}
			curr[j] = min
		}
		prev, curr = curr, prev
	}
	return prev[len(b)]
}

// suggestFlag returns the closest known flag name to the unknown string, or "" if none is close enough.
func suggestFlag(unknown string, cmd *cobra.Command) string {
	unknown = strings.TrimLeft(unknown, "-")
	best := ""
	bestDist := 4 // only consider distance <= 3
	check := func(name string) {
		d := levenshteinDistance(unknown, name)
		if d < bestDist && d*5 <= len(unknown)*2 {
			bestDist = d
			best = name
		}
	}
	cmd.Flags().VisitAll(func(f *pflag.Flag) {
		check(f.Name)
	})
	cmd.InheritedFlags().VisitAll(func(f *pflag.Flag) {
		check(f.Name)
	})
	return best
}

