// filterFields keeps only the requested dotted JSON paths.
//
// Paths are comma-separated; segments split on "." Arrays traverse element-wise
// so "matches.title,matches.coverage" projects those fields onto each element
// of the matches array. Non-matching keys are dropped. Returns the original raw
// bytes unchanged when paths is empty.
//
// This is the implementation backing the --select flag. Lives in helpers.go
// (rather than the food52-specific file) so future generated commands can call
// it without an extra import hop.
func filterFields(raw json.RawMessage, paths string) json.RawMessage {
	var pathSegs [][]string
	for _, p := range strings.Split(paths, ",") {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		segs := strings.Split(p, ".")
		for i := range segs {
			segs[i] = strings.ToLower(segs[i])
		}
		pathSegs = append(pathSegs, segs)
	}
	if len(pathSegs) == 0 {
		return raw
	}
	return filterFieldsRec(raw, pathSegs)
}

func filterFieldsRec(raw json.RawMessage, paths [][]string) json.RawMessage {
	var arr []json.RawMessage
	if err := json.Unmarshal(raw, &arr); err == nil {
		out := make([]json.RawMessage, len(arr))
		for i, el := range arr {
			out[i] = filterFieldsRec(el, paths)
		}
		result, _ := json.MarshalIndent(out, "", "  ")
		return result
	}
	var obj map[string]json.RawMessage
	if err := json.Unmarshal(raw, &obj); err == nil {
		keepWhole := map[string]bool{}
		subPaths := map[string][][]string{}
		for _, p := range paths {
			if len(p) == 0 {
				continue
			}
			head := p[0]
			if len(p) == 1 {
				keepWhole[head] = true
			} else {
				subPaths[head] = append(subPaths[head], p[1:])
			}
		}
		filtered := map[string]json.RawMessage{}
		for k, v := range obj {
			lower := strings.ToLower(k)
			if keepWhole[lower] {
				filtered[k] = v
				continue
			}
			if subs := subPaths[lower]; subs != nil {
				filtered[k] = filterFieldsRec(v, subs)
			}
		}
		result, _ := json.MarshalIndent(filtered, "", "  ")
		return result
	}
	return raw
}
